            command.CommandText = "BvSpGetSurveyActivityWithAlerts";
            
            if(commandExecutionTimeout.HasValue)
            {
                command.CommandTimeout = commandExecutionTimeout.Value;
            }
            else
            {
                command.CommandTimeout = Framework.Constants.DefaultDatabaseCommandTimeout;
            }
            
            var returnValue = new SqlParameter("@ReturnValue", 0);
