        public static IDataReader ExecuteReader(
                int? BatchID,
                bool? onlyActiveSurveys,
                int? CustomITS1,
                int? CustomITS2,
                int? CustomITS3,
                int? CustomITS4,
                int? CustomITS5,
                bool? onlyCatiInterviews,
                int? commandExecutionTimeout, 
                out int returnValue)
        {
            var disposableResources = new Stack< IDisposable >();
            
            SqlCommand command;
            
            try
            {
                var connectionScope = new ConnectionScope();
                disposableResources.Push(connectionScope);
                
                command = CreateCommand(
                        BatchID,
                        onlyActiveSurveys,
                        CustomITS1,
                        CustomITS2,
                        CustomITS3,
                        CustomITS4,
                        CustomITS5,
                        onlyCatiInterviews,
                        commandExecutionTimeout);
                command.Connection = connectionScope.Connection;
                disposableResources.Push(command);
                
                if (DatabaseTransactionScope.Current != null)
                {
                    command.Transaction = DatabaseTransactionScope.Current.Transaction;
                }

                DataTable dataTable;

                try
                {
                    var reader = command.ExecuteReader();
                    
                    disposableResources.Push(reader);
                    
                    dataTable = new DataTable();
                    
                    dataTable.Load(reader);
                }
                catch (SqlException ex)
                {
                    if(ex.Class == 12)
                    {
                        throw new UserMessageException(ex.Message, ex);
                    }
                    else
                    {
                        throw;
                    }
                }
                
                var returnValueParameter = command.Parameters["@ReturnValue"];
                
                returnValue = returnValueParameter.Value != null ? (int)returnValueParameter.Value : 0;


                return dataTable.CreateDataReader();
            }
            finally
            {
                while(disposableResources.Count != 0)
                {
                    var resource2Dispose = disposableResources.Pop();
                    
                    resource2Dispose.Dispose();
                }
            }
        }

